const express = require('express');
const path = require('path');
const { calculatePrice } = require('./smarthotel');
const app = express();
app.use(express.json());
app.use(express.static('public'));

app.get('/', (req, res) => {
  console.log('GET / called');
  res.send('<h1>SmartHotel Interface</h1><p>Interface en développement...</p>');
});

app.post('/api/book-room', (req, res) => {
  try {
    const { basePrice, nights, guests, season, hasWeekend, seaView, clientType } = req.body;

    // Validation des entrées
    if (typeof basePrice !== 'number' || basePrice <= 0) {
      return res.status(400).json({ success: false, error: 'basePrice must be a positive number' });
    }
    if (typeof nights !== 'number' || nights <= 0 || !Number.isInteger(nights)) {
      return res.status(400).json({ success: false, error: 'nights must be a positive integer' });
    }
    if (typeof guests !== 'number' || guests <= 0 || !Number.isInteger(guests)) {
      return res.status(400).json({ success: false, error: 'guests must be a positive integer' });
    }
  
    if (typeof season !== 'string' || !['Haute', 'Basse'].includes(season)) {
      return res.status(400).json({ success: false, error: 'season must be "Haute" or "Basse"' });
    }
  
    if (typeof hasWeekend !== 'boolean') {
      return res.status(400).json({ success: false, error: 'hasWeekend must be a boolean' });
    }
    
    if (typeof seaView !== 'boolean') {
      return res.status(400).json({ success: false, error: 'seaView must be a boolean' });
    }
    if (typeof clientType !== 'string' || !['VIP', 'Standard'].includes(clientType)) {
      return res.status(400).json({ success: false, error: 'clientType must be "VIP" or "Standard"' });
    }
    const result = calculatePrice(basePrice, nights, guests, season, hasWeekend, seaView, clientType);
    res.json({ success: true, ...result });
  } catch (error) {
    console.error('Error processing request:', error);
    res.status(500).json({ success: false, error: 'Internal server error' });
  }
});

// Export app for testing
module.exports = app;

// Only start server if this file is run directly (not imported)
if (require.main === module) {
  app.listen(3000, () => console.log('SmartHotel API running on http://localhost:3000'));
}

const calculatePrice = (basePrice, nights, guests, season, hasWeekend, seaView, clientType) => {
  const seasonMultiplier  = season === 'Haute' ? 1.5 : 1.0;
  const weekendMultiplier = hasWeekend ? 1.2 : 1.0;
  const longStayDiscount  = nights > 7 ? 0.85 : 1.0;
  const seaViewExtra      = seaView ? 30 * nights : 0;
  const breakfastCost     = clientType === 'VIP' ? 0 : 15 * guests * nights;
  const adjustedNightlyRate = basePrice * seasonMultiplier;
  const baseTotal           = adjustedNightlyRate * nights;
  const afterWeekend        = baseTotal * weekendMultiplier;
  const afterDiscount       = afterWeekend * longStayDiscount;
  const grandTotal          = afterDiscount + seaViewExtra + breakfastCost;
  return {
    breakdown: { baseTotal, afterWeekend, afterDiscount, seaViewExtra, breakfastCost },
    grandTotal: Math.round(grandTotal * 100) / 100,
  };
};

module.exports = { calculatePrice };

const request = require('supertest');
const app = require('../index');

describe('SmartHotel API', () => {
  test('GET / should return welcome message', async () => {
    const response = await request(app).get('/');
    expect(response.status).toBe(200);
    expect(response.text).toContain('SmartHotel');
  });

  test('POST /api/book-room should calculate price with valid data', async () => {
    const response = await request(app)
      .post('/api/book-room')
      .send({
        basePrice: 100,
        nights: 2,
        guests: 2,
        season: 'Basse',
        hasWeekend: false,
        seaView: false,
        clientType: 'Standard'
      });

    expect(response.status).toBe(200);
    expect(response.body.success).toBe(true);
    // baseTotal: 200, breakfast: 60, grandTotal: 260
    expect(response.body.grandTotal).toBe(260);
    expect(response.body.breakdown.baseTotal).toBe(200);
    expect(response.body.breakdown.breakfastCost).toBe(60);
  });

  test('should reject invalid basePrice', async () => {
    const response = await request(app)
      .post('/api/book-room')
      .send({
        basePrice: -50,
        nights: 1,
        guests: 1,
        season: 'Basse',
        hasWeekend: false,
        seaView: false,
        clientType: 'Standard'
      });

    expect(response.status).toBe(400);
    expect(response.body.success).toBe(false);
    expect(response.body.error).toContain('basePrice');
  });

  test('should reject non-integer nights', async () => {
    const response = await request(app)
      .post('/api/book-room')
      .send({
        basePrice: 100,
        nights: 1.5,
        guests: 1,
        season: 'Basse',
        hasWeekend: false,
        seaView: false,
        clientType: 'Standard'
      });

    expect(response.status).toBe(400);
    expect(response.body.error).toContain('nights');
  });

  test('should validate season value', async () => {
    const response = await request(app)
      .post('/api/book-room')
      .send({
        basePrice: 100,
        nights: 1,
        guests: 1,
        season: 'Invalid',
        hasWeekend: false,
        seaView: false,
        clientType: 'Standard'
      });

    expect(response.status).toBe(400);
    expect(response.body.error).toContain('season');
  });

  test('should validate clientType value', async () => {
    const response = await request(app)
      .post('/api/book-room')
      .send({
        basePrice: 100,
        nights: 1,
        guests: 1,
        season: 'Basse',
        hasWeekend: false,
        seaView: false,
        clientType: 'Bronze'
      });

    expect(response.status).toBe(400);
    expect(response.body.error).toContain('clientType');
  });

  test('should handle missing required fields', async () => {
    const response = await request(app)
      .post('/api/book-room')
      .send({
        basePrice: 100
      });

    expect(response.status).toBe(400);
    expect(response.body.success).toBe(false);
  });

  test('should calculate price with VIP client (free breakfast)', async () => {
    const response = await request(app)
      .post('/api/book-room')
      .send({
        basePrice: 100,
        nights: 3,
        guests: 2,
        season: 'Haute',
        hasWeekend: true,
        seaView: true,
        clientType: 'VIP'
      });

    expect(response.status).toBe(200);
    expect(response.body.success).toBe(true);
    // baseTotal: 100 * 1.5 * 3 = 450
    // afterWeekend: 450 * 1.2 = 540
    // afterDiscount: 540 * 1.0 = 540 (3 nights <= 7)
    // seaViewExtra: 30 * 3 = 90
    // breakfast: 0
    // total: 540 + 90 = 630
    expect(response.body.grandTotal).toBe(630);
    expect(response.body.breakdown.breakfastCost).toBe(0);
  });
});

const { calculatePrice } = require('../smarthotel');

describe('calculatePrice', () => {
  test('should calculate price with base case', () => {
    const result = calculatePrice(100, 1, 1, 'Basse', false, false, 'Standard');
    expect(result.grandTotal).toBe(115); // 100 + 15 breakfast
    expect(result.breakdown.baseTotal).toBe(100);
    expect(result.breakdown.afterWeekend).toBe(100);
    expect(result.breakdown.afterDiscount).toBe(100);
    expect(result.breakdown.seaViewExtra).toBe(0);
    expect(result.breakdown.breakfastCost).toBe(15);
  });

  test('should apply season multiplier for Haute season', () => {
    const result = calculatePrice(100, 1, 1, 'Haute', false, false, 'Standard');
    expect(result.grandTotal).toBe(165); // 150 + 15 breakfast
    expect(result.breakdown.baseTotal).toBe(150);
    expect(result.breakdown.afterWeekend).toBe(150);
    expect(result.breakdown.afterDiscount).toBe(150);
  });

  test('should apply weekend multiplier', () => {
    const result = calculatePrice(100, 1, 1, 'Basse', true, false, 'Standard');
    expect(result.grandTotal).toBe(135); // 120 + 15 breakfast
    expect(result.breakdown.afterWeekend).toBe(120);
    expect(result.breakdown.afterDiscount).toBe(120);
  });

  test('should apply long stay discount for nights > 7', () => {
    const result = calculatePrice(100, 8, 1, 'Basse', false, false, 'Standard');
    // baseTotal: 100 * 8 = 800
    // afterWeekend: 800 (no weekend)
    // afterDiscount: 800 * 0.85 = 680
    // seaViewExtra: 0
    // breakfastCost: 15 * 1 * 8 = 120
    // grandTotal: 680 + 0 + 120 = 800
    expect(result.breakdown.baseTotal).toBe(800);
    expect(result.breakdown.afterDiscount).toBe(680);
    expect(result.grandTotal).toBe(800);
  });

  test('should add sea view extra', () => {
    const result = calculatePrice(100, 2, 1, 'Basse', false, true, 'Standard');
    expect(result.breakdown.seaViewExtra).toBe(60); // 30 * 2 nights
    expect(result.breakdown.breakfastCost).toBe(30); // 15 * 1 * 2
    expect(result.grandTotal).toBe(290); // 200 + 0 + 60 + 30
  });

  test('should waive breakfast for VIP clients', () => {
    const result = calculatePrice(100, 1, 1, 'Basse', false, false, 'VIP');
    expect(result.breakdown.breakfastCost).toBe(0);
    expect(result.grandTotal).toBe(100);
  });

  test('should apply all modifiers correctly', () => {
    const result = calculatePrice(200, 10, 2, 'Haute', true, true, 'Standard');
    // Season: 200 * 1.5 = 300 per night
    // baseTotal: 300 * 10 = 3000
    // afterWeekend: 3000 * 1.2 = 3600
    // afterDiscount: 3600 * 0.85 = 3060
    // seaViewExtra: 30 * 10 = 300
    // breakfastCost: 15 * 2 * 10 = 300
    // grandTotal: 3060 + 300 + 300 = 3660
    expect(result.breakdown.baseTotal).toBe(3000);
    expect(result.breakdown.afterWeekend).toBe(3600);
    expect(result.breakdown.afterDiscount).toBe(3060);
    expect(result.breakdown.seaViewExtra).toBe(300);
    expect(result.breakdown.breakfastCost).toBe(300);
    expect(result.grandTotal).toBe(3660);
  });
});
